#!/usr/bin/env node

const path = require('path')
const { detect, needsFallback, detectBuildOutput } = require('../lib/index')

const args = process.argv.slice(2)
const jsonMode = args.includes('--json')
const distMode = args.includes('--dist')
const targetPath = args.find(a => !a.startsWith('--'))
const resolvedPath = targetPath ? path.resolve(targetPath) : process.cwd()

// 根据模式选择检测方式
const result = distMode
  ? detectBuildOutput(resolvedPath)
  : detect(resolvedPath)

if (jsonMode) {
  console.log(JSON.stringify(result, null, 2))
  process.exit(0)
}

// 美观输出
const TYPE_LABELS = {
  spa: '\x1b[32m SPA (单页应用) \x1b[0m',
  mpa: '\x1b[33m MPA (多页应用) \x1b[0m',
  hybrid: '\x1b[36m Hybrid (混合应用) \x1b[0m',
  ssg: '\x1b[35m SSG (静态站点生成) \x1b[0m',
  unknown: '\x1b[31m Unknown (未知) \x1b[0m',
}

const CONFIDENCE_LABELS = {
  high: '\x1b[32mhigh\x1b[0m',
  medium: '\x1b[33mmedium\x1b[0m',
  low: '\x1b[31mlow\x1b[0m',
}

console.log()
console.log(`\x1b[1m📋 is-spa-project 检测报告${distMode ? '（构建产物模式）' : ''}\x1b[0m`)
console.log('─'.repeat(50))
console.log(`  ${distMode ? '产物路径' : '项目路径'}:   ${resolvedPath}`)
console.log(`  项目类型:   ${TYPE_LABELS[result.type]}`)
console.log(`  置信度:     ${CONFIDENCE_LABELS[result.confidence]}`)
console.log(`  判定原因:   ${result.reason}`)

const fallback = result.type === 'spa' || result.type === 'hybrid'
console.log(`  回源兜底:   ${fallback ? '\x1b[32m✅ 需要（部署时应配置 fallback 到 index.html）\x1b[0m' : '\x1b[33m❌ 不需要（每个路由有对应 HTML）\x1b[0m'}`)
console.log()

if (distMode) {
  // 构建产物模式的详情
  const details = result.details
  if (details.appHtmlFiles && details.appHtmlFiles.length > 0) {
    console.log('\x1b[1m  📄 应用 HTML 文件\x1b[0m')
    for (const html of details.appHtmlFiles) {
      const icon = html.hasRouterJs ? '🟢' : '⚪'
      const bodyLabel = html.bodyEmpty ? '(空壳)' : '(有内容)'
      console.log(`    ${icon} ${html.name} — ${html.scriptCount} 个 JS ${bodyLabel}${html.hasRouterJs ? ' [含路由]' : ''}`)
    }
    console.log()
  }
  if (details.staticHtmlFiles && details.staticHtmlFiles.length > 0) {
    console.log('\x1b[1m  📑 纯静态 HTML（无 JS 引用）\x1b[0m')
    for (const name of details.staticHtmlFiles) {
      console.log(`    📄 ${name}`)
    }
    console.log()
  }
  if (details.routerJsFiles && details.routerJsFiles.length > 0) {
    console.log('\x1b[1m  🔀 包含路由代码的 JS\x1b[0m')
    for (const name of details.routerJsFiles) {
      console.log(`    📦 ${name}`)
    }
    console.log()
  }
} else {
  // 源码模式的详情
  const { router, entries, framework } = result.details
  console.log('\x1b[1m  🔍 检测详情\x1b[0m')
  console.log()

  if (framework.name) {
    console.log(`  框架:       ${framework.name}`)
  }

  console.log(`  路由依赖:   ${router.hasRouterDependency ? '✅ ' + router.routerLibrary : '❌ 未检测到'}`)
  console.log(`  路由目录:   ${router.hasRouterDirectory ? '✅ 存在' : '❌ 不存在'}`)
  console.log(`  路由使用:   ${router.hasRouterUsageInEntry ? '✅ 入口中使用' : '❌ 入口中未使用'}`)
  console.log(`  构建工具:   ${entries.buildTool}`)
  console.log(`  入口总数:   ${entries.totalEntryCount}`)
  console.log(`  使用路由:   ${entries.routerEntryCount} 个入口`)

  if (entries.entryFiles && entries.entryFiles.length > 0) {
    console.log()
    console.log('\x1b[1m  📦 入口文件\x1b[0m')
    for (const entry of entries.entryFiles) {
      const routerIcon = entry.usesRouter ? '🟢' : '⚪'
      console.log(`    ${routerIcon} ${entry.name} → ${entry.outputHtml}`)
      console.log(`       ${entry.path}`)
    }
  }
  console.log()
}

console.log('─'.repeat(50))
console.log()
